<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Desktop Environment</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body, html {
            width: 100%;
            height: 100%;
            font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, Cantarell, sans-serif;
            overflow: hidden;
        }

        #desktop {
            width: 100%;
            height: 100%;
            background: linear-gradient(135deg, #1e1e2e 0%, #2d2d44 100%);
            display: flex;
            flex-direction: column;
        }

        #taskbar {
            height: 48px;
            background: rgba(0, 0, 0, 0.6);
            border-top: 1px solid rgba(255, 255, 255, 0.1);
            display: flex;
            align-items: center;
            padding: 0 12px;
            gap: 8px;
        }

        .launcher-btn {
            height: 36px;
            padding: 0 16px;
            background: linear-gradient(180deg, #404050 0%, #303040 100%);
            color: #ffffff;
            border: 1px solid rgba(255, 255, 255, 0.2);
            border-radius: 4px;
            cursor: pointer;
            font-size: 13px;
            font-weight: 500;
            transition: all 0.2s ease;
            display: flex;
            align-items: center;
            gap: 8px;
        }

        .launcher-btn:hover {
            background: linear-gradient(180deg, #505060 0%, #404050 100%);
            border-color: rgba(255, 255, 255, 0.3);
        }

        .launcher-btn:active {
            background: linear-gradient(180deg, #303040 0%, #404050 100%);
        }

        .desktop-area {
            flex: 1;
            position: relative;
            overflow: hidden;
        }

        .window {
            position: absolute;
            background: #2d2d3d;
            border: 1px solid rgba(255, 255, 255, 0.1);
            border-radius: 6px;
            box-shadow: 0 10px 40px rgba(0, 0, 0, 0.5);
            display: none;
            flex-direction: column;
            min-width: 360px;
            min-height: 240px;
        }

        .window.active {
            display: flex;
        }

        .window-title {
            height: 32px;
            background: linear-gradient(180deg, #404050 0%, #303040 100%);
            border-bottom: 1px solid rgba(255, 255, 255, 0.1);
            display: flex;
            align-items: center;
            padding: 0 12px;
            color: #ffffff;
            font-size: 13px;
            font-weight: 500;
            cursor: move;
            border-radius: 6px 6px 0 0;
            user-select: none;
        }

        .window-controls {
            margin-left: auto;
            display: flex;
            gap: 8px;
        }

        .win-close {
            width: 24px;
            height: 24px;
            background: rgba(255, 67, 67, 0.2);
            border: 1px solid rgba(255, 67, 67, 0.3);
            border-radius: 3px;
            cursor: pointer;
            color: #ff6b6b;
            font-size: 14px;
            display: flex;
            align-items: center;
            justify-content: center;
            transition: all 0.2s ease;
        }

        .win-close:hover {
            background: rgba(255, 67, 67, 0.3);
            border-color: rgba(255, 67, 67, 0.5);
        }

        .window-content {
            flex: 1;
            overflow: hidden;
            display: flex;
            flex-direction: column;
            padding: 12px;
        }

        /* Files App */
        #files-window {
            width: 600px;
            height: 400px;
            top: 60px;
            left: 20px;
        }

        .files-container {
            display: flex;
            flex-direction: column;
            height: 100%;
        }

        .files-nav {
            display: flex;
            gap: 8px;
            margin-bottom: 12px;
            align-items: center;
        }

        #files-up {
            padding: 6px 12px;
            background: rgba(255, 255, 255, 0.1);
            color: #ffffff;
            border: 1px solid rgba(255, 255, 255, 0.2);
            border-radius: 3px;
            cursor: pointer;
            font-size: 12px;
            transition: all 0.2s ease;
        }

        #files-up:hover {
            background: rgba(255, 255, 255, 0.15);
        }

        #files-path {
            flex: 1;
            padding: 6px 8px;
            background: rgba(0, 0, 0, 0.3);
            color: #b0b0c0;
            font-size: 12px;
            font-family: 'Monaco', 'Courier New', monospace;
            border-radius: 3px;
            border: 1px solid rgba(255, 255, 255, 0.1);
            overflow: hidden;
            text-overflow: ellipsis;
            white-space: nowrap;
        }

        #files-list {
            flex: 1;
            overflow-y: auto;
            border: 1px solid rgba(255, 255, 255, 0.1);
            border-radius: 3px;
            background: rgba(0, 0, 0, 0.2);
        }

        .fs-item {
            padding: 8px 12px;
            color: #e0e0e0;
            cursor: pointer;
            border-bottom: 1px solid rgba(255, 255, 255, 0.05);
            font-size: 13px;
            user-select: none;
            transition: all 0.15s ease;
        }

        .fs-item:hover {
            background: rgba(255, 255, 255, 0.1);
            color: #ffffff;
        }

        .fs-item.folder::before {
            content: "📁 ";
            margin-right: 4px;
        }

        .fs-item.file::before {
            content: "📄 ";
            margin-right: 4px;
        }

        /* Notepad App */
        #notepad-window {
            width: 700px;
            height: 500px;
            top: 100px;
            left: 650px;
        }

        .notepad-container {
            display: flex;
            flex-direction: column;
            height: 100%;
        }

        .tabs-bar {
            display: flex;
            gap: 4px;
            border-bottom: 1px solid rgba(255, 255, 255, 0.1);
            padding: 4px;
            background: rgba(0, 0, 0, 0.3);
            min-height: 40px;
            align-items: center;
        }

        #tabs {
            display: flex;
            gap: 4px;
            flex: 1;
            align-items: center;
        }

        .tab {
            padding: 8px 14px;
            background: rgba(255, 255, 255, 0.05);
            color: #b0b0c0;
            border: 1px solid rgba(255, 255, 255, 0.1);
            border-radius: 4px 4px 0 0;
            cursor: pointer;
            font-size: 12px;
            transition: all 0.2s ease;
            user-select: none;
            max-width: 150px;
            overflow: hidden;
            text-overflow: ellipsis;
            white-space: nowrap;
        }

        .tab:hover {
            background: rgba(255, 255, 255, 0.08);
            color: #ffffff;
        }

        .tab.active {
            background: linear-gradient(180deg, #3a3a4a 0%, #2d2d3d 100%);
            color: #ffffff;
            border-color: rgba(255, 255, 255, 0.2);
        }

        #new-tab {
            padding: 6px 10px;
            background: rgba(255, 255, 255, 0.1);
            color: #ffffff;
            border: 1px solid rgba(255, 255, 255, 0.2);
            border-radius: 3px;
            cursor: pointer;
            font-size: 12px;
            transition: all 0.2s ease;
        }

        #new-tab:hover {
            background: rgba(255, 255, 255, 0.15);
            border-color: rgba(255, 255, 255, 0.3);
        }

        #editor {
            flex: 1;
            background: rgba(0, 0, 0, 0.3);
            color: #e0e0e0;
            border: none;
            padding: 12px;
            font-family: 'Monaco', 'Courier New', monospace;
            font-size: 13px;
            line-height: 1.5;
            resize: none;
            outline: none;
        }

        #editor::placeholder {
            color: #606070;
        }

        #files-list::-webkit-scrollbar,
        #editor::-webkit-scrollbar {
            width: 8px;
        }

        #files-list::-webkit-scrollbar-track,
        #editor::-webkit-scrollbar-track {
            background: rgba(255, 255, 255, 0.05);
        }

        #files-list::-webkit-scrollbar-thumb,
        #editor::-webkit-scrollbar-thumb {
            background: rgba(255, 255, 255, 0.2);
            border-radius: 4px;
        }

        #files-list::-webkit-scrollbar-thumb:hover,
        #editor::-webkit-scrollbar-thumb:hover {
            background: rgba(255, 255, 255, 0.3);
        }
    </style>
</head>
<body>
    <div id="desktop">
        <div id="taskbar">
            <button class="launcher-btn" id="open-files">📁 Files</button>
            <button class="launcher-btn" id="open-notepad">📝 Notepad</button>
        </div>

        <div class="desktop-area">
            <div id="files-window" class="window">
                <div class="window-title">
                    Files
                    <div class="window-controls">
                        <div class="win-close">×</div>
                    </div>
                </div>
                <div class="window-content">
                    <div class="files-container">
                        <div class="files-nav">
                            <button id="files-up">⬅ Up</button>
                            <div id="files-path">/</div>
                        </div>
                        <div id="files-list"></div>
                    </div>
                </div>
            </div>

            <div id="notepad-window" class="window">
                <div class="window-title">
                    Notepad
                    <div class="window-controls">
                        <div class="win-close">×</div>
                    </div>
                </div>
                <div class="window-content">
                    <div class="notepad-container">
                        <div class="tabs-bar">
                            <div id="tabs"></div>
                            <button id="new-tab">+ New</button>
                        </div>
                        <textarea id="editor" placeholder="Start typing..."></textarea>
                    </div>
                </div>
            </div>
        </div>
    </div>

    <script>
        const filesystem = {
            '/': {
                type: 'folder',
                children: {
                    'bin': { type: 'folder', children: {} },
                    'etc': { type: 'folder', children: {} },
                    'home': {
                        type: 'folder',
                        children: {
                            'user': {
                                type: 'folder',
                                children: {
                                    'Documents': { type: 'folder', children: {} },
                                    'Downloads': { type: 'folder', children: {} },
                                    'Pictures': { type: 'folder', children: {} },
                                    'readme.txt': { type: 'file' }
                                }
                            }
                        }
                    },
                    'usr': { type: 'folder', children: {} },
                    'var': { type: 'folder', children: {} }
                }
            }
        };

        let tabs = [];
        let activeTabId = null;
        let currentPath = '/';

        function init() {
            initializeNotepad();
            displayFilesList('/');
            setupWindowControls();
            setupFileNavigation();
            setupNotepadTabs();
        }

        function setupWindowControls() {
            const filesWindow = document.getElementById('files-window');
            const notepadWindow = document.getElementById('notepad-window');

            document.getElementById('open-files').addEventListener('click', () => {
                filesWindow.classList.add('active');
            });

            document.getElementById('open-notepad').addEventListener('click', () => {
                notepadWindow.classList.add('active');
            });

            document.querySelectorAll('.win-close').forEach((btn, idx) => {
                btn.addEventListener('click', () => {
                    if (idx === 0) filesWindow.classList.remove('active');
                    else notepadWindow.classList.remove('active');
                });
            });

            makeWindowsDraggable();
        }

        function makeWindowsDraggable() {
            document.querySelectorAll('.window').forEach(win => {
                const titleBar = win.querySelector('.window-title');
                let isDown = false;
                let offsetX = 0;
                let offsetY = 0;

                titleBar.addEventListener('mousedown', (e) => {
                    if (e.target.classList.contains('win-close')) return;
                    isDown = true;
                    const rect = win.getBoundingClientRect();
                    offsetX = e.clientX - rect.left;
                    offsetY = e.clientY - rect.top;
                });

                document.addEventListener('mousemove', (e) => {
                    if (!isDown) return;
                    win.style.left = (e.clientX - offsetX) + 'px';
                    win.style.top = (e.clientY - offsetY) + 'px';
                });

                document.addEventListener('mouseup', () => {
                    isDown = false;
                });
            });
        }

        function getNodeAtPath(path) {
            if (path === '/') return filesystem['/'];
            const parts = path.split('/').filter(Boolean);
            let current = filesystem['/'];
            for (const part of parts) {
                if (current.children && current.children[part]) {
                    current = current.children[part];
                } else {
                    return null;
                }
            }
            return current;
        }

        function displayFilesList(path) {
            currentPath = path;
            document.getElementById('files-path').textContent = path || '/';
            const list = document.getElementById('files-list');
            list.innerHTML = '';

            const node = getNodeAtPath(path);
            if (!node || node.type !== 'folder') return;

            const entries = Object.entries(node.children || {})
                .sort((a, b) => {
                    if (a[1].type !== b[1].type) {
                        return a[1].type === 'folder' ? -1 : 1;
                    }
                    return a[0].localeCompare(b[0]);
                });

            entries.forEach(([name, item]) => {
                const div = document.createElement('div');
                div.className = `fs-item ${item.type}`;
                div.textContent = name;

                if (item.type === 'folder') {
                    div.addEventListener('dblclick', () => {
                        const newPath = path === '/' ? '/' + name : path + '/' + name;
                        displayFilesList(newPath);
                    });
                }

                list.appendChild(div);
            });
        }

        function setupFileNavigation() {
            document.getElementById('files-up').addEventListener('click', () => {
                if (currentPath === '/') return;
                const parts = currentPath.split('/').filter(Boolean);
                parts.pop();
                const newPath = parts.length === 0 ? '/' : '/' + parts.join('/');
                displayFilesList(newPath);
            });
        }

        function initializeNotepad() {
            const stored = localStorage.getItem('notepad-tabs');
            if (stored) {
                tabs = JSON.parse(stored);
            } else {
                tabs = [{ id: Date.now(), title: 'Untitled', content: '' }];
            }

            activeTabId = tabs[0]?.id || null;
            renderTabs();
            updateEditor();
        }

        function renderTabs() {
            const tabsContainer = document.getElementById('tabs');
            tabsContainer.innerHTML = '';

            tabs.forEach(tab => {
                const tabEl = document.createElement('div');
                tabEl.className = `tab ${tab.id === activeTabId ? 'active' : ''}`;
                tabEl.textContent = tab.title;

                tabEl.addEventListener('click', () => {
                    activeTabId = tab.id;
                    renderTabs();
                    updateEditor();
                });

                tabsContainer.appendChild(tabEl);
            });

            saveTabs();
        }

        function updateEditor() {
            const editor = document.getElementById('editor');
            const activeTab = tabs.find(t => t.id === activeTabId);
            editor.value = activeTab?.content || '';
        }

        function setupNotepadTabs() {
            const editor = document.getElementById('editor');
            const newTabBtn = document.getElementById('new-tab');

            editor.addEventListener('input', (e) => {
                const activeTab = tabs.find(t => t.id === activeTabId);
                if (activeTab) {
                    activeTab.content = e.target.value;
                    saveTabs();
                }
            });

            newTabBtn.addEventListener('click', () => {
                const newId = Date.now();
                tabs.push({ id: newId, title: `Untitled ${tabs.length}`, content: '' });
                activeTabId = newId;
                renderTabs();
                updateEditor();
            });
        }

        function saveTabs() {
            localStorage.setItem('notepad-tabs', JSON.stringify(tabs));
        }

        init();
    </script>
</body>
</html>
